const jobs = $input.first().json.jobs || [];
return jobs.map(job => ({
  json: {
    title: (job.title || '').trim(),
    company: (job.company_name || '').trim(),
    location: (job.candidate_required_location || '').trim() || null,
    remote_type: 'remote',
    apply_url: job.url,
    source: 'remotive',
    description: job.description || null,
    posted_at: job.publication_date ? new Date(job.publication_date).toISOString() : null
  }
})).filter(item => item.json.title && item.json.apply_url);

const jobs = $input.first().json.data || [];
return jobs.map(job => ({
  json: {
    title: (job.title || '').trim(),
    company: (job.company_name || '').trim(),
    location: (job.location || '').trim() || null,
    remote_type: job.remote ? 'remote' : 'onsite',
    apply_url: job.url,
    source: 'arbeitnow',
    description: job.description || null,
    posted_at: job.created_at ? new Date(job.created_at * 1000).toISOString() : null
  }
})).filter(item => item.json.title && item.json.apply_url);

const out = [];
for (const item of $input.all()) {
  const results = item.json.results || [];
  for (const job of results) {
    const locationText = (job.locations || []).map(l => l.name).join(', ');
    const text = `${job.name || ''} ${locationText}`.toLowerCase();
    out.push({
      json: {
        title: (job.name || '').trim(),
        company: (job.company && job.company.name || '').trim(),
        location: locationText || null,
        remote_type: (text.includes('flexible') || text.includes('remote')) ? 'remote' : 'onsite',
        apply_url: job.refs && job.refs.landing_page,
        source: 'themuse',
        description: job.contents || null,
        posted_at: job.publication_date ? new Date(job.publication_date).toISOString() : null
      }
    });
  }
}
return out.filter(item => item.json.title && item.json.apply_url);

const jobs = $input.first().json.results || [];
return jobs.map(job => {
  const text = `${job.title || ''} ${job.description || ''}`.toLowerCase();
  return {
    json: {
      title: (job.title || '').trim(),
      company: (job.company && job.company.display_name || '').trim(),
      location: (job.location && job.location.display_name || '').trim() || null,
      remote_type: text.includes('remote') ? 'remote' : (text.includes('hybrid') ? 'hybrid' : 'onsite'),
      apply_url: job.redirect_url,
      source: 'adzuna',
      description: job.description || null,
      posted_at: job.created ? new Date(job.created).toISOString() : null
    }
  };
}).filter(item => item.json.title && item.json.apply_url);

const jobs = $input.first().json.jobs || [];
return jobs.map(job => {
  const text = `${job.title || ''} ${job.snippet || ''}`.toLowerCase();
  return {
    json: {
      title: (job.title || '').trim(),
      company: (job.company || '').trim(),
      location: (job.location || '').trim() || null,
      remote_type: text.includes('remote') ? 'remote' : (text.includes('hybrid') ? 'hybrid' : 'onsite'),
      apply_url: job.link,
      source: 'jooble',
      description: job.snippet || null,
      posted_at: job.updated ? new Date(job.updated).toISOString() : null
    }
  };
}).filter(item => item.json.title && item.json.apply_url);

const arr = $input.first().json;
const jobs = Array.isArray(arr) ? arr.filter(j => j && j.id) : [];
return jobs.map(job => ({
  json: {
    title: (job.position || '').trim(),
    company: (job.company || '').trim(),
    location: (job.location || '').trim() || null,
    remote_type: 'remote',
    apply_url: job.url,
    source: 'remoteok',
    description: job.description || null,
    posted_at: job.date ? new Date(job.date).toISOString() : null
  }
})).filter(item => item.json.title && item.json.apply_url);

return $input.all().map(item => {
  const raw = item.json;
  const titleFull = raw.title || '';
  const splitIdx = titleFull.indexOf(':');
  const company = splitIdx > -1 ? titleFull.slice(0, splitIdx).trim() : null;
  const title = splitIdx > -1 ? titleFull.slice(splitIdx + 1).trim() : titleFull.trim();
  return {
    json: {
      title,
      company,
      location: raw.region || null,
      remote_type: 'remote',
      apply_url: raw.link,
      source: 'weworkremotely',
      description: raw.contentSnippet || raw.content || raw.summary || null,
      posted_at: raw.pubDate ? new Date(raw.pubDate).toISOString() : (raw.isoDate || null)
    }
  };
}).filter(item => item.json.title && item.json.apply_url);

const jobs = $input.first().json.jobs || $input.first().json.data || [];
return jobs.map(job => {
  const location = Array.isArray(job.locationRestrictions) ? job.locationRestrictions.join(', ') : (job.locationRestrictions || null);
  return {
    json: {
      title: (job.title || '').trim(),
      company: (job.companyName || '').trim(),
      location: location || null,
      remote_type: 'remote',
      apply_url: job.applicationLink || job.guid || null,
      source: 'himalayas',
      description: job.description || job.excerpt || null,
      posted_at: job.pubDate ? new Date(typeof job.pubDate === 'number' ? job.pubDate * 1000 : job.pubDate).toISOString() : null
    }
  };
}).filter(item => item.json.title && item.json.apply_url);

const jobs = $input.first().json.jobs || [];
return jobs.map(job => ({
  json: {
    title: (job.jobTitle || '').trim(),
    company: (job.companyName || '').trim(),
    location: (job.jobGeo || '').trim() || null,
    remote_type: 'remote',
    apply_url: job.url,
    source: 'jobicy',
    description: job.jobDescription || job.jobExcerpt || null,
    posted_at: job.pubDate ? new Date(job.pubDate).toISOString() : null
  }
})).filter(item => item.json.title && item.json.apply_url);

function stripHtml(html) {
  if (!html) return null;
  return html
    .replace(/<[^>]*>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#0?39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim() || null;
}

return $input.all().map(item => ({
  json: { ...item.json, description: stripHtml(item.json.description) }
}));

const includeKeywords = ['intern', 'graduate', 'junior', 'entry level', 'associate', '0-1 years', '0-2 years', 'no experience', 'trainee'];
const excludeKeywords = ['5+ years', 'senior only', 'unpaid', 'commission-only', 'commission only'];

const out = [];
for (const item of $input.all()) {
  const text = `${item.json.title || ''} ${item.json.description || ''}`.toLowerCase();

  const isExcluded = excludeKeywords.some(k => text.includes(k));
  if (isExcluded) continue;

  const entryLevel = includeKeywords.some(k => text.includes(k));
  out.push({ json: { ...item.json, entry_level: entryLevel } });
}
return out;

const suspiciousKeywords = [
  'pay to apply', 'training fee', 'registration fee', 'whatsapp only', 'whatsapp-only',
  'crypto', 'trading platform', 'forex', 'investment opportunity'
];

return $input.all().map(item => {
  const text = `${item.json.title || ''} ${item.json.description || ''}`.toLowerCase();
  const noCompanyName = !item.json.company || item.json.company.trim().length === 0;
  const keywordHit = suspiciousKeywords.some(k => text.includes(k));
  const unrealisticSalary = /\$\s?\d{4,}\s*\/\s*(day|hour)/i.test(text) || /earn\s+\$?\d{3,}[,\d]*\s+per\s+week/i.test(text);

  return {
    json: {
      ...item.json,
      flagged_suspicious: keywordHit || noCompanyName || unrealisticSalary
    }
  };
});

const hasSalaryMention = text => /\$|salary|per annum|per year|per month|\bpkr\b|\busd\b|k\/year/i.test(text);

return $input.all().map(item => {
  const j = item.json;
  const text = `${j.title || ''} ${j.description || ''}`;
  let score = 0;

  if (hasSalaryMention(text)) score += 20;

  if (j.posted_at) {
    const daysOld = (Date.parse(j.posted_at) ? (new Date() - new Date(j.posted_at)) / (1000 * 60 * 60 * 24) : 999);
    if (daysOld <= 7) score += 20;
  }

  if (j.remote_type === 'remote' || j.remote_type === 'hybrid') score += 15;
  if (j.entry_level) score += 15;
  if (j.apply_url) score += 10;

  if (j.flagged_suspicious) score -= 50;
  if (!hasSalaryMention(text) && !j.description) score -= 10;

  score = Math.max(0, Math.min(100, score));

  return { json: { ...j, score } };
});
